UPDATE tmp_prj SET ent_id = (SELECT ent_id FROM amb_hr_entities WHERE ent_code = 'KR01') WHERE comp_prj_no = 14021;
-- 루트(prj_no=1)는 KR01로 기본 매핑
UPDATE tmp_prj SET ent_id = (SELECT ent_id FROM amb_hr_entities WHERE ent_code = 'KR01') WHERE ent_id IS NULL;

-- ============================================================
-- 4) kms_projects INSERT (380건)
--    PRJ_TYPE 매핑: P→PROJECT, B→BUSINESS, S→SALES, M→MANAGEMENT, E→ETC
--    STATUS 매핑: 1→APPROVED, 3→CLOSED, 4→soft delete
-- ============================================================
INSERT INTO kms_projects (
  pjt_id, ent_id, pjt_code, pjt_name, pjt_summary,
  pjt_status, pjt_category, pjt_priority,
  pjt_proposer_id, pjt_manager_id, pjt_dept_id,
  pjt_start_date, pjt_end_date,
  pjt_parent_id,
  pjt_note, pjt_original_lang,
  pjt_created_at, pjt_updated_at,
  pjt_deleted_at
)
SELECT
  t.new_pjt_id,
  t.ent_id,
  -- pjt_code: PRJ_SERIAL 사용, 없으면 HM-{PRJ_NO}
  CASE WHEN t.prj_serial != '' THEN t.prj_serial ELSE 'HM-' || t.prj_no END,
  LEFT(t.prj_name, 300),
  NULLIF(t.prj_contents, ''),
  -- pjt_status
  CASE t.status WHEN 1 THEN 'APPROVED' WHEN 3 THEN 'CLOSED' ELSE 'APPROVED' END,
  -- pjt_category (PRJ_TYPE)
  CASE t.prj_type
    WHEN 'P' THEN 'PROJECT'
    WHEN 'B' THEN 'BUSINESS'
    WHEN 'S' THEN 'SALES'
    WHEN 'M' THEN 'MANAGEMENT'
    WHEN 'E' THEN 'ETC'
    ELSE 'ETC'
  END,
  'MEDIUM',
  -- pjt_proposer_id: REG_USER_NO → UUID (fallback to first admin)
  COALESCE(
    (SELECT map_target_pk FROM amb_migration_pk_map WHERE map_source_table = 'tbl_user' AND map_source_pk = t.reg_user_no AND map_target_table = 'amb_users' LIMIT 1),
    (SELECT usr_id FROM amb_users WHERE usr_email LIKE '%@saeha%' LIMIT 1)
  ),
  -- pjt_manager_id: LEADER_NO → UUID
  (SELECT map_target_pk FROM amb_migration_pk_map WHERE map_source_table = 'tbl_user' AND map_source_pk = t.leader_no AND map_target_table = 'amb_users' LIMIT 1),
  -- pjt_dept_id: ORG_NO → UUID (부서 매핑, 없으면 NULL)
  CASE WHEN t.org_no > 0 THEN
    (SELECT map_target_pk FROM amb_migration_pk_map WHERE map_source_table = 'tbl_org' AND map_source_pk = t.org_no AND map_target_table = 'amb_units' LIMIT 1)
  ELSE NULL END,
  t.start_date,
  t.end_date,
  -- pjt_parent_id: UP_PRJ_NO → UUID (자기참조 제외)
  CASE WHEN t.up_prj_no != t.prj_no THEN
    (SELECT p2.new_pjt_id FROM tmp_prj p2 WHERE p2.prj_no = t.up_prj_no)
  ELSE NULL END,
  -- pjt_note: 원본 메타데이터 보존
  '[hanmam] PRJ_NO=' || t.prj_no || ' LEVEL=' || t.prj_level || ' ORDER=' || t.prj_order
    || ' LABOR=' || t.labor_rule || ' EXPENSE=' || t.expense_rule || ' SHOW=' || t.show_rule
    || ' BUDGET=' || t.budget_rule || ' PRODUCT=' || t.product_no,
  'ko',
  t.reg_datetime,
  t.reg_datetime,
  -- soft delete: STATUS=4 → deleted_at 설정
  CASE WHEN t.status = 4 THEN t.reg_datetime ELSE NULL END
FROM tmp_prj t
ORDER BY t.prj_level, t.prj_no;

-- ============================================================
-- 5) PK 매핑 기록
-- ============================================================
INSERT INTO amb_migration_pk_map (map_source_table, map_source_pk, map_target_table, map_target_pk)
SELECT 'tbl_prj', prj_no, 'kms_projects', new_pjt_id
FROM tmp_prj;

-- ============================================================
-- 6) kms_project_members INSERT (325건)
--    USER_TYPE: 1→MANAGER, 2→MEMBER
-- ============================================================
CREATE TEMP TABLE tmp_prj_user (
  prj_user_no   INT PRIMARY KEY,
  prj_no        INT,
  user_no       INT,
  user_type     INT,
  start_date    DATE,
  end_date      DATE,
  work_rate     INT,
  reg_dt        TIMESTAMP
);

