INSERT INTO kms_project_members (
  pjt_id, usr_id, pmb_role, pmb_is_active,
  pmb_joined_at, pmb_left_at,
  pmb_created_at, pmb_updated_at
)
SELECT
  tp.new_pjt_id,
  um.map_target_pk,
  CASE tpu.user_type WHEN 1 THEN 'MANAGER' ELSE 'MEMBER' END,
  true,
  tpu.start_date,
  CASE WHEN tpu.end_date < CURRENT_DATE THEN tpu.end_date ELSE NULL END,
  tpu.reg_dt,
  tpu.reg_dt
FROM tmp_prj_user tpu
JOIN tmp_prj tp ON tp.prj_no = tpu.prj_no
JOIN amb_migration_pk_map um ON um.map_source_table = 'tbl_user'
  AND um.map_source_pk = tpu.user_no
  AND um.map_target_table = 'amb_users'
